#[derive(Clone, Copy, PartialEq)]
pub enum Menu {
    Alignment,
    Borders,
    CellStyle,
    Clickable,
    Cols,
    Complex,
    Dynamic,
    Fixed,
    Focusable,
    Hello,
    LeafStyle,
    Margin,
    Pad,
    Popup,
    Progress,
    Rows,
    Weighted,
}

static CURRENT_MENU: Mutex<Option<Menu>> = Mutex::new(None);
static FOCUSED: Mutex<Option<usize>> = Mutex::new(None);
static LAST_DRAWN_FOCUS: Mutex<Option<usize>> = Mutex::new(Some(usize::MAX));

use std::sync::atomic::{AtomicUsize, Ordering};
static PROG_1_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_2_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static PROG_3_PREV: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_1_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_2_END: AtomicUsize = AtomicUsize::new(usize::MAX);
static DYN_3_END: AtomicUsize = AtomicUsize::new(usize::MAX);

pub trait Callbacks {
    fn quit(&mut self);
    fn action(&mut self, args: &[&str]);
    fn click(&mut self);
    fn nav(&mut self, args: &[&str]);
}

pub fn to_menu(name: &str) -> Option<Menu> {
    match name {
        "Alignment" => Some(Menu::Alignment),
        "Borders" => Some(Menu::Borders),
        "CellStyle" => Some(Menu::CellStyle),
        "Clickable" => Some(Menu::Clickable),
        "Cols" => Some(Menu::Cols),
        "Complex" => Some(Menu::Complex),
        "Dynamic" => Some(Menu::Dynamic),
        "Fixed" => Some(Menu::Fixed),
        "Focusable" => Some(Menu::Focusable),
        "Hello" => Some(Menu::Hello),
        "LeafStyle" => Some(Menu::LeafStyle),
        "Margin" => Some(Menu::Margin),
        "Pad" => Some(Menu::Pad),
        "Popup" => Some(Menu::Popup),
        "Progress" => Some(Menu::Progress),
        "Rows" => Some(Menu::Rows),
        "Weighted" => Some(Menu::Weighted),
        _ => None,
    }
}

pub fn update_events<C: Callbacks>(events: &[InputEvent], state: &mut C) {
    for ev in events {
        if let InputEvent::Quit = ev { state.quit(); return; }
    }
    match *CURRENT_MENU.lock().unwrap() {
        Some(Menu::Alignment) => update_events_alignment(events, state),
        Some(Menu::Borders) => update_events_borders(events, state),
        Some(Menu::CellStyle) => update_events_cellstyle(events, state),
        Some(Menu::Clickable) => update_events_clickable(events, state),
        Some(Menu::Cols) => update_events_cols(events, state),
        Some(Menu::Complex) => update_events_complex(events, state),
        Some(Menu::Dynamic) => update_events_dynamic(events, state),
        Some(Menu::Fixed) => update_events_fixed(events, state),
        Some(Menu::Focusable) => update_events_focusable(events, state),
        Some(Menu::Hello) => update_events_hello(events, state),
        Some(Menu::LeafStyle) => update_events_leafstyle(events, state),
        Some(Menu::Margin) => update_events_margin(events, state),
        Some(Menu::Pad) => update_events_pad(events, state),
        Some(Menu::Popup) => update_events_popup(events, state),
        Some(Menu::Progress) => update_events_progress(events, state),
        Some(Menu::Rows) => update_events_rows(events, state),
        Some(Menu::Weighted) => update_events_weighted(events, state),
        None => {}
    }
}

pub fn update_menu(backend: &mut dyn Backend, menu: Menu) {
    let mut current = CURRENT_MENU.lock().unwrap();
    if *current != Some(menu) {
        *current = Some(menu);
        drop(current);
        *FOCUSED.lock().unwrap() = None;
        *LAST_DRAWN_FOCUS.lock().unwrap() = None;
        PROG_1_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_2_PREV.store(usize::MAX, Ordering::Relaxed);
        PROG_3_PREV.store(usize::MAX, Ordering::Relaxed);
        DYN_1_END.store(usize::MAX, Ordering::Relaxed);
        DYN_2_END.store(usize::MAX, Ordering::Relaxed);
        DYN_3_END.store(usize::MAX, Ordering::Relaxed);
        match menu {
            Menu::Alignment => draw_alignment(backend),
            Menu::Borders => draw_borders(backend),
            Menu::CellStyle => draw_cellstyle(backend),
            Menu::Clickable => draw_clickable(backend),
            Menu::Cols => draw_cols(backend),
            Menu::Complex => draw_complex(backend),
            Menu::Dynamic => draw_dynamic(backend),
            Menu::Fixed => draw_fixed(backend),
            Menu::Focusable => draw_focusable(backend),
            Menu::Hello => draw_hello(backend),
            Menu::LeafStyle => draw_leafstyle(backend),
            Menu::Margin => draw_margin(backend),
            Menu::Pad => draw_pad(backend),
            Menu::Popup => draw_popup(backend),
            Menu::Progress => draw_progress(backend),
            Menu::Rows => draw_rows(backend),
            Menu::Weighted => draw_weighted(backend),
        }
    }
}

pub fn force_redraw() {
    *CURRENT_MENU.lock().unwrap() = None;
}

pub fn update_params(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    match *CURRENT_MENU.lock().unwrap() {
        Some(Menu::Alignment) => update_params_alignment(backend, changes),
        Some(Menu::Borders) => update_params_borders(backend, changes),
        Some(Menu::CellStyle) => update_params_cellstyle(backend, changes),
        Some(Menu::Clickable) => update_params_clickable(backend, changes),
        Some(Menu::Cols) => update_params_cols(backend, changes),
        Some(Menu::Complex) => update_params_complex(backend, changes),
        Some(Menu::Dynamic) => update_params_dynamic(backend, changes),
        Some(Menu::Fixed) => update_params_fixed(backend, changes),
        Some(Menu::Focusable) => update_params_focusable(backend, changes),
        Some(Menu::Hello) => update_params_hello(backend, changes),
        Some(Menu::LeafStyle) => update_params_leafstyle(backend, changes),
        Some(Menu::Margin) => update_params_margin(backend, changes),
        Some(Menu::Pad) => update_params_pad(backend, changes),
        Some(Menu::Popup) => update_params_popup(backend, changes),
        Some(Menu::Progress) => update_params_progress(backend, changes),
        Some(Menu::Rows) => update_params_rows(backend, changes),
        Some(Menu::Weighted) => update_params_weighted(backend, changes),
        None => {}
    }
    backend.flush();
}

