fn update_params_dynamic(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One" || n == "parameter Two") {
        for &(name, val) in changes {
            match name {
                "parameter One" => {
                    let end_x = backend.blit(atlas_3(), 11, 216, val);
                    let prev = DYN_1_END.swap(end_x, Ordering::Relaxed);
                    if prev != usize::MAX && prev > end_x {
                        backend.fill_rect(end_x, 216, prev - end_x, 32, rgb!(0, 0, 0));
                    }
                }
                "parameter Two" => {
                    let end_x = backend.blit(atlas_3(), 11, 381, val);
                    let prev = DYN_2_END.swap(end_x, Ordering::Relaxed);
                    if prev != usize::MAX && prev > end_x {
                        backend.fill_rect(end_x, 381, prev - end_x, 32, rgb!(0, 0, 0));
                    }
                }
                _ => {}
            }
        }
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_dynamic(backend, focused);
        }
    }
}

