fn update_params_progress(backend: &mut dyn Backend, changes: &[(&str, &str)]) {
    if changes.iter().any(|&(n, _)| n == "parameter One") {
        for &(name, val) in changes {
            if name == "parameter One" {
                let end_x = backend.blit(atlas_3(), 411, 409, val);
                let prev = DYN_3_END.swap(end_x, Ordering::Relaxed);
                if prev != usize::MAX && prev > end_x {
                    backend.fill_rect(end_x, 409, prev - end_x, 32, rgb!(0, 0, 0));
                }
            }
        }
    }
    for &(name, val) in changes {
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (798.0_f32 * v) as usize;
                let prev = PROG_1_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(1, 151, filled, 108, rgb!(255, 255, 255)); }
                        if filled < 798 { backend.fill_rect(1 + filled, 151, 798 - filled, 108, rgb!(0, 0, 0)); }
                    } else if filled > prev {
                        backend.fill_rect(1 + prev, 151, filled - prev, 108, rgb!(255, 255, 255));
                    } else {
                        backend.fill_rect(1 + filled, 151, prev - filled, 108, rgb!(0, 0, 0));
                    }
                }
            }
        }
        if name == "parameter Two" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (778.0_f32 * v) as usize;
                let prev = PROG_2_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(11, 271, filled, 88, rgb!(0, 255, 0)); }
                        if filled < 778 { backend.fill_rect(11 + filled, 271, 778 - filled, 88, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(11 + prev, 271, filled - prev, 88, rgb!(0, 255, 0));
                    } else {
                        backend.fill_rect(11 + filled, 271, prev - filled, 88, rgb!(40, 40, 40));
                    }
                }
            }
        }
        if name == "parameter One" {
            if let Ok(v) = val.parse::<f32>() {
                let v = v.clamp(0.0, 1.0);
                let filled = (378.0_f32 * v) as usize;
                let prev = PROG_3_PREV.swap(filled, Ordering::Relaxed);
                if filled != prev {
                    if prev == usize::MAX {
                        if filled > 0 { backend.fill_rect(11, 381, filled, 88, rgb!(0, 0, 255)); }
                        if filled < 378 { backend.fill_rect(11 + filled, 381, 378 - filled, 88, rgb!(40, 40, 40)); }
                    } else if filled > prev {
                        backend.fill_rect(11 + prev, 381, filled - prev, 88, rgb!(0, 0, 255));
                    } else {
                        backend.fill_rect(11 + filled, 381, prev - filled, 88, rgb!(40, 40, 40));
                    }
                }
            }
        }
    }
    {
        let focused = *FOCUSED.lock().unwrap();
        let mut last = LAST_DRAWN_FOCUS.lock().unwrap();
        if *last != focused {
            *last = focused;
            drop(last);
            draw_focus_progress(backend, focused);
        }
    }
}

